@op
def extract():
    return [1, 2, 3]

@job
def my_pipeline():
    extract()

daily_schedule = ScheduleDefinition(
    job=my_pipeline,
    cron_schedule="0 6 * * *",
    execution_timezone="America/New_York",
)

defs = Definitions(
    jobs=[my_pipeline],
    schedules=[daily_schedule],
)

