import time
import boto3
from prefect import flow, task

@task(retries=20, retry_delay_seconds=120)  # Poll every 2 min, up to 40 minutes
def wait_for_s3_file(bucket: str, key: str) -> bool:
    s3 = boto3.client("s3")
    try:
        s3.head_object(Bucket=bucket, Key=key)
        return True
    except s3.exceptions.ClientError:
        raise Exception(f"File not yet available: s3://{bucket}/{key}")

@task
def process_file(bucket: str, key: str):
    print(f"Processing s3://{bucket}/{key}")

@flow
def s3_triggered_pipeline(bucket: str, key: str):
    file_ready = wait_for_s3_file(bucket, key)
    process_file(bucket, key, wait_for=[file_ready])

from dagster import sensor, RunRequest, SensorEvaluationContext
import boto3

@sensor(job=process_s3_file_job, minimum_interval_seconds=60)
def s3_file_sensor(context: SensorEvaluationContext):
    s3 = boto3.client("s3")

    # Get a cursor from last evaluation to avoid reprocessing
    cursor = context.cursor or "0"

    response = s3.list_objects_v2(
        Bucket="my-data-bucket",
        Prefix="incoming/",
    )

    new_files = [
        obj["Key"] for obj in response.get("Contents", [])
        if obj["LastModified"].timestamp() > float(cursor)
    ]

    for file_key in new_files:
        yield RunRequest(
            run_key=file_key,          # Idempotency key — Dagster won't re-run same key
            run_config={"ops": {"process": {"config": {"s3_key": file_key}}}},
        )

    # Update cursor to current time
    if new_files:
        context.update_cursor(str(max(
            obj["LastModified"].timestamp()
            for obj in response.get("Contents", [])
        )))
